// Validate and prepare video job
const { jobId, userId, style, lyrics, audioUrl } = $input.item.json;

// Validate required fields
if (!jobId || !userId || !style || !lyrics) {
  throw new Error('Missing required fields');
}

// Create job record
const job = {
  jobId,
  userId,
  style,
  lyrics,
  audioUrl,
  status: 'queued',
  progress: 0,
  createdAt: new Date().toISOString(),
  steps: {
    upload: 'pending',
    audioAnalysis: 'pending',
    visualGeneration: 'pending',
    rendering: 'pending',
    upload: 'pending'
  }
};

return { job };

// Parse audio analysis results
const audioAnalysis = {
  beats: [],
  bpm: 120,
  duration: 180,
  key: 'C',
  energy: 'medium'
};

// PHOTOREALISTIC prompts - indistinguishable from reality
const realismPrefix = 'Ultra-realistic photograph, shot on Canon EOS R5, 85mm lens, f/1.4 aperture, natural lighting, shallow depth of field, 8K resolution, photorealistic, RAW sensor data, natural textures, realistic shadows, film grain, ';

const realismSuffix = ', photorealistic, no AI artifacts, natural imperfections, realistic grain, authentic colors, depth of field, volumetric lighting, cinematic quality, professional photography';

const stylePrompts = {
  photorealistic: {
    prefix: 'Ultra-realistic photograph, shot on Canon EOS R5, 85mm lens, f/1.4, natural lighting, ',
    prompt: 'authentic moment, candid composition, realistic textures, natural shadows, shallow depth of field',
    suffix: ', photorealistic, 8K, RAW quality, film grain, authentic colors'
  },
  documentary: {
    prefix: 'Documentary photograph, National Geographic style, raw authentic, ',
    prompt: 'photojournalism, 35mm film, natural moment, candid human expressions, realistic lighting',
    suffix: ', unedited, authentic, realistic grain, natural colors, depth of field'
  },
  cinematic: {
    prefix: 'Cinematic film still, shot on ARRI Alexa, anamorphic lens, ',
    prompt: 'Hollywood production quality, volumetric lighting, realistic atmosphere, natural shadows',
    suffix: ', 4K RAW, film grain, realistic depth, cinematic color grading'
  },
  urban: {
    prefix: 'Street photography, urban environment, candid authentic, ',
    prompt: 'natural lighting, realistic shadows, city atmosphere, 50mm lens, f/2.8 bokeh',
    suffix: ', photojournalistic style, realistic textures, natural grain, authentic moment'
  },
  portrait: {
    prefix: 'Professional portrait photography, studio lighting, ',
    prompt: 'realistic skin texture, visible pores, natural hair strands, authentic expression, 105mm portrait lens',
    suffix: ', realistic depth, editorial quality, natural imperfections, shallow DOF'
  },
  musicvideo: {
    prefix: 'Music video cinematography, professional grade camera, ',
    prompt: 'realistic lighting, natural colors, volumetric light rays, cinematic depth of field',
    suffix: ', 4K RAW footage, Steadicam shot, authentic atmosphere, realistic grain'
  }
};

// Get style configuration
const style = $input.item.json.style || 'photorealistic';
const styleConfig = stylePrompts[style] || stylePrompts.photorealistic;

// Generate frame prompts with photorealistic enhancement
const lyrics = $input.item.json.lyrics;
const lines = lyrics.split('\n').filter(l => l.trim());

const frames = lines.map((line, i) => {
  const basePrompt = `${styleConfig.prefix}${styleConfig.prompt}, ${line}${styleConfig.suffix}`;

  return {
    text: line,
    startTime: i * 4,
    endTime: (i + 1) * 4,
    prompt: basePrompt,
    realismSettings: {
      addFilmGrain: true,
      addChromaticAberration: true,
      addVignette: true,
      addMotionBlur: false,
      depthOfField: 'f/1.4',
      colorGrading: 'cinematic'
    }
  };
});

return {
  jobId: $input.item.json.jobId,
  audioAnalysis,
  frames,
  style,
  realismLevel: 'maximum',
  photorealistic: true
};
